const FEED_URL = 'https://news.google.com/rss/search?q=artificial+intelligence&hl=en-US&gl=US&ceid=US:en';
const SOURCE_NAME = 'AI RSS Feed';

const normalized = items
  .map(({ json }) => {
    const rawDate = json.isoDate || json.pubDate || json.published_at || new Date().toISOString();
    const parsedDate = new Date(rawDate);
    const publishedAt = Number.isNaN(parsedDate.getTime()) ? new Date().toISOString() : parsedDate.toISOString();

    return {
      guid: json.guid || json.link || json.url || `${json.title || 'article'}-${publishedAt}`,
      title: json.title || 'Untitled article',
      url: json.link || json.url,
      link: json.link || json.url,
      source_name: SOURCE_NAME,
      source_url: FEED_URL,
      contentSnippet: json.contentSnippet || json.content || json.summary || '',
      content: json.content || json.contentSnippet || '',
      published_at: publishedAt,
      image_url: (json.enclosure && json.enclosure.url) ? json.enclosure.url : (json.image_url || null)
    };
  })
  .filter((item) => Boolean(item.url));

normalized.sort((a, b) => new Date(b.published_at).getTime() - new Date(a.published_at).getTime());

return normalized.slice(0, 3).map((article) => ({ json: article }));

const configuredBlogTags = ['AI News', 'AI Tools Directory'];

const itemsForIngest = items.map(({ json }) => {
  let aiSummary = null;
  let aiAnalysis = null;

  const content = json.choices?.[0]?.message?.content;
  if (typeof content === 'string' && content.trim()) {
    try {
      const parsed = JSON.parse(content);
      aiSummary = typeof parsed.summary === 'string' ? parsed.summary.trim() : null;
      aiAnalysis = typeof parsed.analysis === 'string' ? parsed.analysis.trim() : null;
    } catch {
      aiSummary = null;
      aiAnalysis = null;
    }
  }

  const fallback = (json.contentSnippet || json.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const fallbackSummary = fallback ? (fallback.length > 300 ? `${fallback.slice(0, 297)}...` : fallback) : null;
  const summary = aiSummary || fallbackSummary;
  const combinedSummary = aiAnalysis && summary ? `${summary}\n\nWhy it matters: ${aiAnalysis}` : summary;

  const grokImageUrl =
    json.data?.[0]?.url ||
    json.data?.[0]?.image_url ||
    json.image_url ||
    null;

  return {
    guid: json.guid || json.url || json.link,
    title: json.title,
    url: json.url || json.link,
    summary: combinedSummary,
    source_name: json.source_name || 'AI RSS Feed',
    source_url: json.source_url || 'https://news.google.com/rss/search?q=artificial+intelligence&hl=en-US&gl=US&ceid=US:en',
    image_url: grokImageUrl,
    published_at: json.published_at || new Date().toISOString()
  };
});

return [{
  json: {
    items: itemsForIngest,
    source_name: 'AI RSS Feed',
    source_url: 'https://news.google.com/rss/search?q=artificial+intelligence&hl=en-US&gl=US&ceid=US:en',
    sync_to_blog: true,
    blog_tags: configuredBlogTags
  }
}];
